import scala.collection.mutable.Queue

def solve(grid: Array[Array[Long]], k: Long): Long = {
    val m = grid.length
    val n = grid(0).length
    var count = 0L
    for (i <- 0 until m) {
        for (j <- 0 until n) {
            if (grid(i)(j) > 0) {
                val queue = Queue[(Int, Int)]((i, j))
                var sum = 0L
                while (queue.nonEmpty) {
                    val (x, y) = queue.dequeue()
                    sum += grid(x)(y)
                    grid(x)(y) = 0L
                    for (dx <- Array(-1, 1, 0, 0); dy <- Array(0, 0, -1, 1)) {
                        val nx = x + dx
                        val ny = y + dy
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid(nx)(ny) > 0) {
                            queue.enqueue((nx, ny))
                        }
                    }
                }
                if (sum % k == 0) count += 1
            }
        }
    }
    count
}
```

