import scala.collection.mutable.Queue

def solve(grid: Array[Array[Long]], k: Long): Long = {
  var count = 0L
  val m = grid.length
  val n = grid(0).length

  for (i <- 0 until m) {
    for (j <- 0 until n) {
      if (grid(i)(j) > 0) {
        val queue = Queue[(Int, Int)]()
        queue.enqueue((i, j))
        var sum = 0L
        while (queue.nonEmpty) {
          val (x, y) = queue.dequeue()
          sum += grid(x)(y)
          grid(x)(y) = 0L
          for (dx <- List(-1, 1, 0, 0); dy <- List(0, 0, -1, 1)) {
            val nx = x + dx
            val ny = y + dy
            if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid(nx)(ny) > 0) {
              queue.enqueue((nx, ny))
            }
          }
        }
        if (sum % k == 0) {
          count += 1
        }
      }
    }
  }
  count
}
