                let sum = 0;
                while (queue.length > 0) {
                    const [x, y] = queue.shift()!;
                    sum += grid[x][y];
                    grid[x][y] = 0;
                    for (const [dx, dy] of [[-1, 0], [1, 0], [0, -1], [0, 1]]) {
                        const nx = x + dx;
                        const ny = y + dy;
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0) {
                            queue.push([nx, ny]);
                        }
                    }
                }
                if (sum % k === 0) {
                    count++;
                }
            }
        }
    }
    return count;
}
